import{_ as t,o as n,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"71. Paid Union Meetings","description":"","frontmatter":{"title":"71. Paid Union Meetings","eba":"Health Allied & Managers Admin 2021-2025","topics":["union-matters","staffing"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/union-matters/71-paid-union-meetings.md","filePath":"ebas/has-managers-admin/common-terms/union-matters/71-paid-union-meetings.md"}'),o={name:"ebas/has-managers-admin/common-terms/union-matters/71-paid-union-meetings.md"};function s(r,e,m,p,d,g){return n(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_71-paid-union-meetings" tabindex="-1">71. Paid Union Meetings <a class="header-anchor" href="#_71-paid-union-meetings" aria-label="Permalink to &quot;71. Paid Union Meetings&quot;">​</a></h1><p><strong>71.1</strong> In order for the Employer to approve paid meetings between the HWU and its members, the HWU must meet the following requirements:</p><p><strong>(a)</strong> the Employer is given reasonable notice that such a meeting is to be held; and</p><p><strong>(b)</strong> the reason/s for the meeting is also to be provided to the Employer with the notice;</p><p><strong>(c)</strong> the location for the meeting is to be agreed between the HWU and the Employer;</p><p><strong>(d)</strong> an acceptable level of staffing will be maintained;</p><p><strong>(e)</strong> where possible meetings will occur at times least disruptive to service delivery;</p><p><strong>(f)</strong> the duration of the paid meeting will not exceed half an hour except where agreed by the HWU and the Employer;</p><p><strong>(g)</strong> the Employees will return to work without industrial action or threat of industrial action.</p><p>Plain language terms: union meeting pay, stop work meeting.</p>',10)])])}const c=t(o,[["render",s]]);export{h as __pageData,c as default};
